import { getFocusables } from './get-focusables';
/**
 * Returns the last focusable element within the container.
 */
export function getLastFocusable({
  container,
  filter
}) {
  const items = getFocusables({
    container,
    filter
  });
  return items.length > 0 ? items[items.length - 1] : null;
}